export function Checkbox({
  id,
  label,
  checked,
  onChange,
  indeterminate = false,
}: {
  id: string
  label: string
  checked: boolean
  onChange: (v: boolean) => void
  indeterminate?: boolean
}) {
  return (
    <label htmlFor={id}>
      <input
        id={id}
        type="checkbox"
        checked={checked}
        ref={(el) => { if (el) el.indeterminate = indeterminate }}
        onChange={(e) => onChange(e.target.checked)}
      />
      {label}
    </label>
  )
}
